import { NextFunction, Response } from 'express';
import prisma from '../config/database';
import { verifyToken } from '../utils/auth';

// Extend Request globally later (see below)
import { Request } from 'express';

export interface AuthRequest extends Request {
  user?: any
  workspaceMember?: any
  channel?: any
  platformAdmin?: any
}

// 🔐 Authenticate user
export const authenticate = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction,
): Promise<void> => {
  try {
    const token = req.headers.authorization?.split(' ')[1];

    if (!token) {
      res.status(401).json({ message: 'No token provided' });
      return;
    }

    const decoded = verifyToken(token);

    if (!decoded) {
      res.status(401).json({ message: 'Invalid or expired token' });
      return;
    }

    const user = await prisma.user.findUnique({
      where: { id: decoded.userId },
    });

    if (!user) {
      res.status(401).json({ message: 'User not found' });
      return;
    }

    req.user = user;
    next();
  } catch (error: any) {
    res.status(500).json({ message: 'Authentication error', error: error.message });
  }
};

// 🏢 Workspace access
export const hasWorkspaceAccess = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction,
): Promise<void> => {
  try {
    const { workspaceId } = req.params;
    const userId = req.user?.id;

    const member = await prisma.workspaceMember.findUnique({
      where: {
        workspaceId_userId: { workspaceId, userId },
      },
    });

    if (!member) {
      res.status(403).json({ message: 'Access denied to this workspace' });
      return;
    }

    req.workspaceMember = member;
    next();
  } catch (error: any) {
    res.status(500).json({ message: 'Authorization error', error: error.message });
  }
};

// 👑 Workspace admin check
export const isWorkspaceAdmin = (
  req: AuthRequest,
  res: Response,
  next: NextFunction,
): void => {
  try {
    if (!req.workspaceMember) {
      res.status(403).json({ message: 'Access denied' });
      return;
    }

    if (!['OWNER', 'ADMIN'].includes(req.workspaceMember.role)) {
      res.status(403).json({ message: 'Admin access required' });
      return;
    }

    next();
  } catch (error: any) {
    res.status(500).json({ message: 'Authorization error', error: error.message });
  }
};

// 📢 Channel access
export const hasChannelAccess = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction,
): Promise<void> => {
  try {
    const { channelId } = req.params;
    const userId = req.user?.id;

    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
      include: { members: true },
    });

    if (!channel) {
      res.status(404).json({ message: 'Channel not found' });
      return;
    }

    if (!channel.isPrivate) {
      const workspaceMember = await prisma.workspaceMember.findUnique({
        where: {
          workspaceId_userId: {
            workspaceId: channel.workspaceId,
            userId,
          },
        },
      });

      if (!workspaceMember) {
        res.status(403).json({ message: 'Access denied to this channel' });
        return;
      }
    } else {
      const member = channel.members.find((m) => m.userId === userId);

      if (!member) {
        res.status(403).json({ message: 'Access denied to this channel' });
        return;
      }
    }

    req.channel = channel;
    next();
  } catch (error: any) {
    res.status(500).json({ message: 'Authorization error', error: error.message });
  }
};

// 🧑‍💼 Platform admin
export const isPlatformAdmin = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction,
): Promise<void> => {
  try {
    const userId = req.user?.id;

    const admin = await prisma.platformAdmin.findUnique({
      where: { userId },
    });

    if (!admin) {
      res.status(403).json({ message: 'Platform admin access required' });
      return;
    }

    req.platformAdmin = admin;
    next();
  } catch (error: any) {
    res.status(500).json({ message: 'Authorization error', error: error.message });
  }
};

import { NextFunction, Request, Response } from 'express';
import { AppError } from '../utils/errors';

/**
 * Global error handling middleware
 */
export const errorHandler = (
  err: any,
  req: Request,
  res: Response,
  _next: NextFunction,
) => {
  // Log error
  console.error({
    message: err.message,
    stack: err.stack,
    path: req.path,
    method: req.method,
    timestamp: new Date().toISOString(),
  });

  if (err instanceof AppError) {
    return res.status(err.statusCode).json({
      success: false,
      statusCode: err.statusCode,
      message: err.message,
      error: {
        code: err.errorCode,
      },
      timestamp: new Date().toISOString(),
    });
  }

  // Prisma errors
  if (err.name === 'PrismaClientKnownRequestError') {
    const statusCode = 400;
    let message = 'Database error';

    if (err.code === 'P2002') {
      message = `${err.meta?.target?.[0]} already exists`;
    } else if (err.code === 'P2025') {
      message = 'Resource not found';
    }

    return res.status(statusCode).json({
      success: false,
      statusCode,
      message,
      error: {
        code: 'DATABASE_ERROR',
      },
      timestamp: new Date().toISOString(),
    });
  }

  // Default error
  return res.status(500).json({
    success: false,
    statusCode: 500,
    message: 'Internal server error',
    error: {
      code: 'INTERNAL_SERVER_ERROR',
    },
    timestamp: new Date().toISOString(),
  });
};

/**
 * 404 Not Found handler
 */
export const notFoundHandler = (
  req: Request,
  res: Response,
  _next: NextFunction,
) => {
  res.status(404).json({
    success: false,
    statusCode: 404,
    message: `Route ${req.originalUrl} not found`,
    error: {
      code: 'NOT_FOUND',
    },
    timestamp: new Date().toISOString(),
  });
};

import morgan, { StreamOptions } from 'morgan';
import logger from '../utils/logger';

// Direct morgan log stream directly through our Winston logger's http level
const stream: StreamOptions = {
  write: (message) => logger.http(message.trim()),
};

// Define custom morgan logging format to capture all status codes and complete request/response diagnostic parameters
const morganMiddleware = morgan(
