import prisma from '../config/database';
import {
  AuthenticationError,
  NotFoundError,
} from '../utils/errors';

export class AdminService {
  /**
   * Dashboard statistics
   */
  async getDashboardStats() {
    const [
      totalUsers,
      totalWorkspaces,
      totalChannels,
      totalMessages,
      totalDirectMessages,
      activeCalls,
      recentUsers,
    ] = await Promise.all([
      prisma.user.count(),
      prisma.workspace.count(),
      prisma.channel.count(),
      prisma.message.count(),
      prisma.directMessage.count(),
      prisma.call.count({
        where: {
          status: {
            in: ['INITIATED', 'ACTIVE'], // keep only valid enums
          },
        },
      }),
      prisma.user.findMany({
        take: 10,
        orderBy: { createdAt: 'desc' },
        select: {
          id: true,
          email: true,
          username: true,
          createdAt: true,
        },
      }),
    ]);

    return {
      totalUsers,
      totalWorkspaces,
      totalChannels,
      totalMessages,
      totalDirectMessages,
      activeCalls,
      recentUsers,
      timestamp: new Date(),
    };
  }

  /**
   * Get all users
   */
  async getUserStats() {
    const users = await prisma.user.findMany({
      include: {
        _count: {
          select: {
            messages: true,
            workspaceMembers: true,
            directMessages: true,
          },
        },
      },
      orderBy: { createdAt: 'desc' },
    });

    return users.map((user) => ({
      userId: user.id,
      username: user.username,
      email: user.email,
      messagesCount: user._count.messages,
      workspacesCount: user._count.workspaceMembers,
      directMessagesCount: user._count.directMessages,
      createdAt: user.createdAt,
      lastActiveAt: user.lastActiveAt,
    }));
  }

  /**
   * Get all workspaces
   */
  async getWorkspaceStats() {
    const workspaces = await prisma.workspace.findMany({
      include: {
        _count: {
          select: {
            members: true,
            channels: true,
          },
        },
        admin: {
          select: {
            id: true,
            username: true,
            email: true,
          },
        },
      },
      orderBy: { createdAt: 'desc' },
    });

    return workspaces.map((ws) => ({
      workspaceId: ws.id,
      name: ws.name,
      membersCount: ws._count.members,
      channelsCount: ws._count.channels,
      createdAt: ws.createdAt,
      admin: ws.admin,
    }));
  }

  /**
   * Get audit logs
   */
  async getAuditLogs(options: {
    page?: number;
    limit?: number;
  }) {
    const page = options.page || 1;
    const limit = Math.min(options.limit || 20, 100);
    const skip = (page - 1) * limit;

    const [logs, total] = await Promise.all([
      prisma.auditLog.findMany({
        orderBy: { createdAt: 'desc' },
        skip,
        take: limit,
      }),
      prisma.auditLog.count(),
    ]);

    return {
      logs,
      pagination: {
        page,
        limit,
        total,
        pages: Math.ceil(total / limit),
      },
    };
  }

  /**
   * Ban user
   */
  async banUser(userId: string, reason: string) {
    if (!userId) {
      throw new AuthenticationError('User ID required');
    }

    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundError('User');
    }

    const updated = await prisma.user.update({
      where: { id: userId },
      data: {
        accountStatus: 'BANNED',
        banReason: reason,
      },
    });

    return updated;
  }

  /**
   * Unban user
   */
  async unbanUser(userId: string) {
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundError('User');
    }

    return prisma.user.update({
      where: { id: userId },
      data: {
        accountStatus: 'ACTIVE',
        banReason: null,
      },
    });
  }

  /**
   * System health
   */
  async getSystemHealth() {
    try {
      await prisma.user.count(); // check DB

      return {
        status: 'healthy',
        database: 'connected',
        uptime: process.uptime(),
        timestamp: new Date(),
      };
    } catch (error) {
      return {
        status: 'unhealthy',
        database: 'disconnected',
        timestamp: new Date(),
      };
    }
  }

  /**
   * Get user details
   */
  async getUserDetails(userId: string) {
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: {
        workspaceMembers: {
          include: {
            workspace: true,
          },
        },
        platformAdmin: true,
      },
    });

    if (!user) {
      throw new NotFoundError('User');
    }
    return user;
  }

  /**
   * Promote user to platform admin
   */
  async promoteToAdmin(userId: string) {
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });
    if (!user) {
      throw new NotFoundError('User');
    }

    return prisma.platformAdmin.upsert({
      where: { userId },
      update: {},
      create: {
        userId,
        role: 'ADMIN',
      },
    });
  }

  /**
   * Remove platform admin privileges
   */
  async removeAdmin(userId: string) {
    try {
      await prisma.platformAdmin.delete({
        where: { userId },
      });
      return { message: 'Platform admin privileges removed' };
    } catch (error) {
      return { message: 'User was not a platform admin' };
    }
  }

  /**
   * Get workspace details
   */
  async getWorkspaceDetails(workspaceId: string) {
    const workspace = await prisma.workspace.findUnique({
      where: { id: workspaceId },
      include: {
        members: {
          include: {
            user: {
              select: {
                id: true,
                username: true,
                email: true,
              },
            },
          },
        },
        channels: true,
      },
    });

    if (!workspace) {
      throw new NotFoundError('Workspace');
    }
    return workspace;
  }

  /**
   * Get all channels across the platform
   */
  async getAllChannels() {
    return prisma.channel.findMany({
      include: {
        workspace: {
          select: {
            id: true,
            name: true,
          },
        },
        _count: {
          select: {
            members: true,
            messages: true,
          },
        },
      },
      orderBy: { createdAt: 'desc' },
    });
  }

  /**
   * Get activity analytics
   */
  async getActivityAnalytics() {
    const [messagesCount, directMessagesCount, callsCount] = await Promise.all([
      prisma.message.count(),
      prisma.directMessage.count(),
      prisma.call.count(),
    ]);

    return {
      messagesCount,
      directMessagesCount,
      callsCount,
      timestamp: new Date(),
    };
  }
}

export default new AdminService();

import prisma from '../config/database';
import { comparePassword, generateToken, hashPassword } from '../utils/auth';
import {
  AuthenticationError,
  ConflictError,
  NotFoundError,
} from '../utils/errors';
import { AccountStatus, UserStatus } from '@prisma/client';

export class AuthService {
  /**
   * Register
   */
  async register(data: {
    email: string;
    username: string;
    password: string;
    firstName?: string;
    lastName?: string;
  }) {
    const existingUser = await prisma.user.findFirst({
      where: {
        OR: [{ email: data.email }, { username: data.username }],
      },
    });

    if (existingUser) {
      throw new ConflictError('Email or username already exists');
    }

    const passwordHash = await hashPassword(data.password);

    const user = await prisma.user.create({
      data: {
        email: data.email,
        username: data.username,
        passwordHash,
        firstName: data.firstName,
        lastName: data.lastName,
        accountStatus: AccountStatus.ACTIVE,
        status: UserStatus.OFFLINE,
      },
    });

    await prisma.notificationSetting.create({
      data: { userId: user.id },
    });

    const token = generateToken(user.id);

    return {
      token,
      user: this.formatUser(user),
    };
  }

  /**
   * Login
   */
  async login(email: string, password: string) {
    const user = await prisma.user.findUnique({
      where: { email },
    });

    if (!user) {
      throw new AuthenticationError('Invalid credentials');
    }

    //Account status check
    if (user.accountStatus === AccountStatus.BANNED) {
      throw new AuthenticationError('Account is banned');
    }

    if (user.accountStatus === AccountStatus.DEACTIVATED) {
      throw new AuthenticationError('Account is deactivated');
    }

    const isValid = await comparePassword(password, user.passwordHash);

    if (!isValid) {
      throw new AuthenticationError('Invalid credentials');
    }

    // ✅ update last active
    await prisma.user.update({
      where: { id: user.id },
      data: {
        lastActiveAt: new Date(),
        status: UserStatus.ONLINE,
      },
    });

    const token = generateToken(user.id);

    return {
      token,
      user: this.formatUser(user),
    };
  }

  /**
   * Get profile
   */
  async getUserProfile(userId: string) {
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundError('User');
    }

    return this.formatUser(user);
  }

  /**
   * Update profile
   */
  async updateProfile(userId: string, data: any) {
    const user = await prisma.user.update({
      where: { id: userId },
      data,
    });

    return this.formatUser(user);
  }

  /**
   * Change password
   */
  async changePassword(userId: string, oldPass: string, newPass: string) {
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundError('User');
    }

    const valid = await comparePassword(oldPass, user.passwordHash);

    if (!valid) {
      throw new AuthenticationError('Invalid current password');
    }

    const passwordHash = await hashPassword(newPass);

    await prisma.user.update({
      where: { id: userId },
      data: { passwordHash },
    });
  }

  /**
   * Refresh token
   */
  async refreshToken(userId: string) {
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user) {
      throw new NotFoundError('User');
    }

    return {
      token: generateToken(user.id),
      user: this.formatUser(user),
    };
  }

  /**
   * Reusable formatter
   */
  private formatUser(user: any) {
    return {
      id: user.id,
      email: user.email,
      username: user.username,
      firstName: user.firstName,
      lastName: user.lastName,
      status: user.status,
      accountStatus: user.accountStatus,
    };
  }
}

export default new AuthService();

import prisma from '../config/database';
import {
  AuthenticationError,
  ConflictError,
  NotFoundError,
} from '../utils/errors';
import { ChannelRole } from '@prisma/client';

export class ChannelService {
  /**
   * Create channel
   */
  async createChannel(
    workspaceId: string,
    userId: string,
    data: { name: string; description?: string; isPrivate?: boolean },
  ) {
    const workspace = await prisma.workspace.findUnique({
      where: { id: workspaceId },
    });
    if (!workspace) {
      throw new NotFoundError('Workspace');
    }

    // ✅ Check user is workspace member
    const member = await prisma.workspaceMember.findUnique({
      where: { workspaceId_userId: { workspaceId, userId } },
    });
    if (!member) {
      throw new AuthenticationError('Access denied');
    }

    const name = data.name.toLowerCase();

    // ✅ Check duplicate
    const exists = await prisma.channel.findFirst({
      where: { workspaceId, name },
    });
    if (exists) {
      throw new ConflictError('Channel already exists');
    }

    // ✅ Create channel
    const channel = await prisma.channel.create({
      data: {
        workspaceId,
        name,
        description: data.description,
        isPrivate: data.isPrivate ?? false,
        createdBy: userId,
      },
    });

    // ✅ Prepare members array
    const members: {
      channelId: string;
      userId: string;
      role: ChannelRole;
    }[] = [
      {
        channelId: channel.id,
        userId,
        role: ChannelRole.OWNER,
      },
    ];

    // ✅ Add all workspace members if public
    if (!data.isPrivate) {
      const workspaceMembers = await prisma.workspaceMember.findMany({
        where: { workspaceId },
        select: { userId: true },
      });

      const additionalMembers = workspaceMembers
        .filter((m) => m.userId !== userId)
        .map((m) => ({
          channelId: channel.id,
          userId: m.userId,
          role: ChannelRole.MEMBER,
        }));

      members.push(...additionalMembers);
    }

    // ✅ Bulk insert
    await prisma.channelMember.createMany({
      data: members,
      skipDuplicates: true,
    });

    return channel;
  }

  /**
   * Get channels
   */
  async getChannels(workspaceId: string, userId: string) {
    const member = await prisma.workspaceMember.findUnique({
      where: { workspaceId_userId: { workspaceId, userId } },
    });

    if (!member) {
      throw new AuthenticationError('Access denied');
    }

    return prisma.channel.findMany({
      where: {
        workspaceId,
        archivedAt: null,
      },
      include: {
        _count: { select: { members: true } },
      },
      orderBy: { createdAt: 'desc' },
    });
  }

  /**
   * Get single channel
   */
  async getChannelById(channelId: string, userId: string) {
    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
      include: { members: true },
    });

    if (!channel) {
      throw new NotFoundError('Channel');
    }

    if (channel.isPrivate) {
      const isMember = channel.members.some((m) => m.userId === userId);
      if (!isMember) {
        throw new AuthenticationError('Access denied');
      }
    }

    return channel;
  }

  /**
   * Update channel
   */
  async updateChannel(
    channelId: string,
    userId: string,
    data: { name?: string; description?: string; topic?: string },
  ) {
    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
      include: { members: true },
    });

    if (!channel) {
      throw new NotFoundError('Channel');
    }

    const member = channel.members.find((m) => m.userId === userId);

    if (
      !member ||
      (member.role !== ChannelRole.OWNER &&
        member.role !== ChannelRole.MODERATOR)
    ) {
      throw new AuthenticationError('Not allowed');
    }

    // ✅ Name conflict check
    if (data.name) {
      const conflict = await prisma.channel.findFirst({
        where: {
          workspaceId: channel.workspaceId,
          name: data.name.toLowerCase(),
          id: { not: channelId },
        },
      });

      if (conflict) {
        throw new ConflictError('Channel name exists');
      }
    }

    return prisma.channel.update({
      where: { id: channelId },
      data: {
        name: data.name?.toLowerCase(),
        description: data.description,
        topic: data.topic,
      },
    });
  }

  /**
   * Delete channel
   */
  async deleteChannel(channelId: string, userId: string) {
    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
      include: { members: true },
    });

    if (!channel) {
      throw new NotFoundError('Channel');
    }

    const member = channel.members.find((m) => m.userId === userId);

    if (member?.role !== ChannelRole.OWNER) {
      throw new AuthenticationError('Only owner can delete');
    }

    await prisma.channel.delete({
      where: { id: channelId },
    });

    return { message: 'Channel deleted' };
  }

  /**
   * Add member
   */
  async addMember(channelId: string, userId: string, targetUserId: string) {
    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
      include: { members: true },
    });

    if (!channel) {
      throw new NotFoundError('Channel');
    }

    const admin = channel.members.find((m) => m.userId === userId);

    if (
      !admin ||
      (admin.role !== ChannelRole.OWNER &&
        admin.role !== ChannelRole.MODERATOR)
    ) {
      throw new AuthenticationError('Not allowed');
    }

    // ✅ Check user exists
    const user = await prisma.user.findUnique({
      where: { id: targetUserId },
    });
    if (!user) {
      throw new NotFoundError('User');
    }

    return prisma.channelMember.upsert({
      where: {
        channelId_userId: { channelId, userId: targetUserId },
      },
      update: {},
      create: {
        channelId,
        userId: targetUserId,
        role: ChannelRole.MEMBER, // ✅ FIX
      },
    });
  }

  /**
   * Remove member
   */
  async removeMember(channelId: string, userId: string, targetUserId: string) {
    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
      include: { members: true },
    });

    if (!channel) {
      throw new NotFoundError('Channel');
    }

    const admin = channel.members.find((m) => m.userId === userId);

    if (
      !admin ||
      (admin.role !== ChannelRole.OWNER &&
        admin.role !== ChannelRole.MODERATOR)
    ) {
      throw new AuthenticationError('Not allowed');
    }

    await prisma.channelMember.deleteMany({
      where: { channelId, userId: targetUserId },
    });

    return { message: 'Member removed' };
  }

  /**
   * Get members
   */
  async getMembers(channelId: string, userId: string) {
    const isMember = await prisma.channelMember.findUnique({
      where: { channelId_userId: { channelId, userId } },
    });

    if (!isMember) {
      throw new AuthenticationError('Access denied');
    }

    return prisma.channelMember.findMany({
      where: { channelId },
      include: {
        user: {
          select: {
            id: true,
            username: true,
            email: true,
            profilePicture: true,
            status: true,
          },
        },
      },
    });
  }

  /**
   * Archive channel
   */
  async archiveChannel(channelId: string, userId: string) {
    const member = await prisma.channelMember.findUnique({
      where: { channelId_userId: { channelId, userId } },
    });

    if (member?.role !== ChannelRole.OWNER) {
      throw new AuthenticationError('Only owner can archive');
    }

    return prisma.channel.update({
      where: { id: channelId },
      data: { archivedAt: new Date() },
    });
  }

  /**
   * Join channel
   */
  async joinChannel(channelId: string, userId: string) {
    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
    });
    if (!channel) {
      throw new NotFoundError('Channel');
    }
    if (channel.isPrivate) {
      throw new AuthenticationError('Cannot join private channel without invite');
    }

    return prisma.channelMember.upsert({
      where: {
        channelId_userId: { channelId, userId },
      },
      update: {},
      create: {
        channelId,
        userId,
        role: ChannelRole.MEMBER,
      },
    });
  }

  /**
   * Leave channel
   */
  async leaveChannel(channelId: string, userId: string) {
    const channel = await prisma.channel.findUnique({
      where: { id: channelId },
    });
    if (!channel) {
      throw new NotFoundError('Channel');
    }

    // Check if user is the last owner
    const member = await prisma.channelMember.findUnique({
      where: { channelId_userId: { channelId, userId } },
    });
    if (!member) {
      throw new NotFoundError('Channel member');
    }

    if (member.role === ChannelRole.OWNER) {
      const owners = await prisma.channelMember.count({
        where: { channelId, role: ChannelRole.OWNER },
      });
      if (owners <= 1) {
        throw new ConflictError('Cannot leave as the last owner');
      }
    }

    await prisma.channelMember.delete({
      where: { channelId_userId: { channelId, userId } },
    });

    return { message: 'Left channel' };
  }

  /**
   * Get pinned messages
   */
  async getPinnedMessages(channelId: string) {
    return prisma.pinnedMessage.findMany({
      where: { channelId },
      include: {
        message: {
          include: {
            user: {
              select: {
                id: true,
                username: true,
                firstName: true,
                lastName: true,
                profilePicture: true,
              },
            },
          },
        },
      },
    });
  }

  /**
   * Pin message
   */
  async pinMessage(channelId: string, messageId: string, pinnedBy: string) {
    const message = await prisma.message.findUnique({
      where: { id: messageId },
    });
    if (message?.channelId !== channelId) {
      throw new NotFoundError('Message in this channel not found');
    }

    return prisma.pinnedMessage.upsert({
      where: {
        messageId_channelId: { messageId, channelId },
      },
      update: {},
      create: {
        messageId,
        channelId,
        pinnedBy,
      },
    });
  }

  /**
   * Unpin message
   */
  async unpinMessage(channelId: string, messageId: string) {
    try {
      await prisma.pinnedMessage.delete({
        where: {
          messageId_channelId: { messageId, channelId },
        },
      });
      return { message: 'Message unpinned' };
    } catch (error) {
      throw new NotFoundError('Pinned message not found');
    }
  }
}

