import prisma from '../config/database';
import {
  AuthenticationError,
  ValidationError,
} from '../utils/errors';

export class SearchService {
  /**
   * Search Messages
   */
  async searchMessages(
    workspaceId: string,
    userId: string,
    query: string,
    options: {
      page?: number;
      limit?: number;
      channelId?: string;
      fromDate?: Date;
      toDate?: Date;
    },
  ) {
    if (!query || query.trim().length < 2) {
      throw new ValidationError('Search query must be at least 2 characters');
    }

    //Check workspace access
    const member = await prisma.workspaceMember.findUnique({
      where: { workspaceId_userId: { workspaceId, userId } },
    });

    if (!member) {
      throw new AuthenticationError('Not a member of this workspace');
    }

    const page = options.page || 1;
    const limit = Math.min(options.limit || 20, 100);
    const skip = (page - 1) * limit;

    const where: any = {
      channel: { workspaceId },
      content: { contains: query, mode: 'insensitive' }, // ✅ safer than search
      deletedAt: null,
    };

    if (options.channelId) {
      where.channelId = options.channelId;
    }

    if (options.fromDate || options.toDate) {
      where.createdAt = {};
      if (options.fromDate) {
        where.createdAt.gte = options.fromDate;
      }
      if (options.toDate) {
        where.createdAt.lte = options.toDate;
      }
    }

    const [messages, total] = await Promise.all([
      prisma.message.findMany({
        where,
        include: {
          user: {
            select: { id: true, username: true, profilePicture: true },
          },
          channel: {
            select: { id: true, name: true },
          },
        },
        orderBy: { createdAt: 'desc' },
        skip,
        take: limit,
      }),
      prisma.message.count({ where }),
    ]);

    return {
      results: messages,
      pagination: {
        page,
        limit,
        total,
        pages: Math.ceil(total / limit),
      },
      query,
    };
  }

  /**
   * 👤 Search Users
   */
  async searchUsers(
    workspaceId: string,
    userId: string,
    query: string,
    options: {
      page?: number;
      limit?: number;
    },
  ) {
    if (!query || query.trim().length < 1) {
      throw new ValidationError('Search query is required');
    }

    const member = await prisma.workspaceMember.findUnique({
      where: { workspaceId_userId: { workspaceId, userId } },
    });

    if (!member) {
      throw new AuthenticationError('Not a member of this workspace');
    }

    const page = options.page || 1;
    const limit = Math.min(options.limit || 20, 100);
    const skip = (page - 1) * limit;

    const [users, total] = await Promise.all([
      prisma.user.findMany({
        where: {
          workspaceMembers: {
            some: { workspaceId },
          },
          OR: [
            { username: { contains: query, mode: 'insensitive' } },
            { email: { contains: query, mode: 'insensitive' } },
            { firstName: { contains: query, mode: 'insensitive' } },
            { lastName: { contains: query, mode: 'insensitive' } },
          ],
        },
        select: {
          id: true,
          username: true,
          email: true,
          firstName: true,
          lastName: true,
          profilePicture: true,
          status: true,
        },
        skip,
        take: limit,
      }),
      prisma.user.count({
        where: {
          workspaceMembers: {
            some: { workspaceId },
          },
          OR: [
            { username: { contains: query, mode: 'insensitive' } },
            { email: { contains: query, mode: 'insensitive' } },
            { firstName: { contains: query, mode: 'insensitive' } },
            { lastName: { contains: query, mode: 'insensitive' } },
          ],
        },
      }),
    ]);

    return {
      results: users,
      pagination: {
        page,
        limit,
        total,
        pages: Math.ceil(total / limit),
      },
      query,
    };
  }

  /**
   * 📁 Search Channels
   */
  async searchChannels(
    workspaceId: string,
    userId: string,
    query: string,
    options: {
      page?: number;
      limit?: number;
    },
  ) {
    if (!query || query.trim().length < 1) {
      throw new ValidationError('Search query is required');
    }

    const member = await prisma.workspaceMember.findUnique({
      where: { workspaceId_userId: { workspaceId, userId } },
    });

    if (!member) {
      throw new AuthenticationError('Not a member of this workspace');
    }

    const page = options.page || 1;
    const limit = Math.min(options.limit || 20, 100);
    const skip = (page - 1) * limit;

    const [channels, total] = await Promise.all([
      prisma.channel.findMany({
        where: {
          workspaceId,
          archivedAt: null,
          OR: [
            { name: { contains: query, mode: 'insensitive' } },
            { description: { contains: query, mode: 'insensitive' } },
          ],
        },
        include: {
          _count: { select: { members: true } },
        },
        skip,
        take: limit,
      }),
      prisma.channel.count({
        where: {
          workspaceId,
          archivedAt: null,
          OR: [
            { name: { contains: query, mode: 'insensitive' } },
            { description: { contains: query, mode: 'insensitive' } },
          ],
        },
      }),
    ]);

    return {
      results: channels,
      pagination: {
        page,
        limit,
        total,
        pages: Math.ceil(total / limit),
      },
      query,
    };
  }

  /**
   * 🌍 Global Search
   */
  async globalSearch(
    workspaceId: string,
    userId: string,
    query: string,
  ) {
    if (!query || query.trim().length < 2) {
      throw new ValidationError('Search query must be at least 2 characters');
    }

    const member = await prisma.workspaceMember.findUnique({
      where: { workspaceId_userId: { workspaceId, userId } },
    });

    if (!member) {
      throw new AuthenticationError('Not a member of this workspace');
    }

    const limit = 5;

    const [messages, users, channels] = await Promise.all([
      prisma.message.findMany({
        where: {
          channel: { workspaceId },
          content: { contains: query, mode: 'insensitive' },
          deletedAt: null,
        },
        take: limit,
      }),
      prisma.user.findMany({
        where: {
          workspaceMembers: { some: { workspaceId } },
          OR: [
            { username: { contains: query, mode: 'insensitive' } },
            { email: { contains: query, mode: 'insensitive' } },
          ],
        },
        take: limit,
      }),
      prisma.channel.findMany({
        where: {
          workspaceId,
          name: { contains: query, mode: 'insensitive' },
        },
        take: limit,
      }),
    ]);

    return { messages, users, channels };
  }

  /**
   * 💬 Search My Messages
   */
  async searchMyMessages(
    userId: string,
    query: string,
    options: {
      page?: number;
      limit?: number;
      workspaceId?: string;
    },
  ) {
    if (!query || query.trim().length < 2) {
      throw new ValidationError('Search query must be at least 2 characters');
    }

    const page = options.page || 1;
    const limit = Math.min(options.limit || 20, 100);
    const skip = (page - 1) * limit;

    const where: any = {
      userId,
      content: { contains: query, mode: 'insensitive' },
      deletedAt: null,
    };

    if (options.workspaceId) {
      where.channel = { workspaceId: options.workspaceId };
    }

    const [messages, total] = await Promise.all([
      prisma.message.findMany({
        where,
        include: {
          channel: {
            select: { id: true, name: true },
          },
        },
        orderBy: { createdAt: 'desc' },
        skip,
        take: limit,
      }),
      prisma.message.count({ where }),
    ]);

    return {
      results: messages,
      pagination: {
        page,
        limit,
        total,
        pages: Math.ceil(total / limit),
      },
      query,
    };
  }
}

export default new SearchService();

import { WorkspaceRole } from '@prisma/client';
import prisma from '../config/database';
import { ConflictError, ErrorCode, NotFoundError } from '../utils/errors';
import { generateSlug } from '../utils/slug';

export class WorkspaceService {
  /**
   * Create a new workspace
   */
  async createWorkspace(data: {
    name: string;
    description?: string;
    slug?: string;
    createdBy: string;
  }) {
    // Generate slug automatically from name if not provided
    let slug = data.slug;
    if (!slug || slug.trim() === '') {
      slug = generateSlug(data.name);
    }

    // Standardize slug to be lowercase
    slug = slug.toLowerCase().trim();

    // Ensure the slug is unique by appending incremental indices if conflicts exist
    let uniqueSlug = slug;
    let counter = 1;
    while (true) {
      const existingWorkspace = await prisma.workspace.findUnique({
        where: { slug: uniqueSlug },
      });

      if (!existingWorkspace) {
        break;
      }

      // If collision occurs and user provided a specific slug, throw error to notify them
      if (data.slug) {
        throw new ConflictError(
          'Workspace slug already exists',
          ErrorCode.WORKSPACE_SLUG_EXISTS,
        );
      }

      // If slug was auto-generated, append a clean incremental suffix to maintain user flow
      uniqueSlug = `${slug}-${counter}`;
      counter++;
    }

    // Create workspace with the resolved unique slug
    const workspace = await prisma.workspace.create({
      data: {
        name: data.name,
        description: data.description,
        slug: uniqueSlug,
        createdBy: data.createdBy,
      },
    });

    // Add creator as owner
    await prisma.workspaceMember.create({
      data: {
        workspaceId: workspace.id,
        userId: data.createdBy,
        role: 'OWNER',
      },
    });

    return workspace;
  }

  /**
   * Get workspace by ID
   */
  async getWorkspaceById(workspaceId: string) {
    const workspace = await prisma.workspace.findUnique({
      where: { id: workspaceId },
      include: {
        members: {
          include: {
            user: {
              select: {
                id: true,
                email: true,
                username: true,
                firstName: true,
                lastName: true,
                profilePicture: true,
                status: true,
              },
            },
          },
        },
        channels: {
          where: { archivedAt: null },
        },
      },
    });

    if (!workspace) {
      throw new NotFoundError('Workspace');
    }

    return workspace;
  }

  /**
   * Get user's workspaces
   */
  async getUserWorkspaces(userId: string) {
    const workspaces = await prisma.workspace.findMany({
      where: {
        members: {
          some: {
            userId,
          },
        },
      },
      include: {
        members: {
          where: { userId },
        },
        channels: {
          where: { archivedAt: null },
        },
      },
    });

    return workspaces;
  }

  /**
   * Update workspace
   */
  async updateWorkspace(
    workspaceId: string,
    data: {
      name?: string;
      description?: string;
    },
  ) {
    const workspace = await prisma.workspace.update({
      where: { id: workspaceId },
      data,
    });

    return workspace;
  }

  /**
   * Add member to workspace
   */
  async addMember(
    workspaceId: string,
    userId: string,
    role: WorkspaceRole = 'MEMBER',
  ) {
    // Check if user already exists
    const existingMember = await prisma.workspaceMember.findUnique({
      where: {
        workspaceId_userId: { workspaceId, userId },
      },
    });

    if (existingMember) {
      throw new ConflictError(
        'User already a member of this workspace',
        ErrorCode.DUPLICATE_MEMBER,
      );
    }

    const member = await prisma.workspaceMember.create({
      data: {
        workspaceId,
        userId,
        role,
      },
    });

    return member;
  }

  /**
   * Remove member from workspace
   */
  async removeMember(workspaceId: string, userId: string) {
    await prisma.workspaceMember.delete({
      where: {
        workspaceId_userId: { workspaceId, userId },
      },
    });

    return { message: 'Member removed successfully' };
  }

  /**
   * Update member role
   */
  async updateMemberRole(workspaceId: string, userId: string, role: WorkspaceRole) {
    const member = await prisma.workspaceMember.update({
      where: {
        workspaceId_userId: { workspaceId, userId },
      },
      data: { role },
    });

    return member;
  }

  /**
   * Get workspace members
   */
  async getMembers(workspaceId: string) {
    const members = await prisma.workspaceMember.findMany({
      where: { workspaceId },
      include: {
        user: {
          select: {
            id: true,
            email: true,
            username: true,
            firstName: true,
            lastName: true,
            profilePicture: true,
            status: true,
          },
        },
      },
    });

    return members;
  }

  /**
   * Send workspace invitation
   */
  async inviteUser(data: {
    workspaceId: string;
    email: string;
    role: WorkspaceRole;
    invitedBy: string;
  }) {
    const expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + 7); // 7 days expiry

    const invitation = await prisma.workspaceInvitation.upsert({
      where: {
        workspaceId_email: {
          workspaceId: data.workspaceId,
          email: data.email,
        },
      },
      update: {
        expiresAt,
        used: false,
      },
      create: {
        workspaceId: data.workspaceId,
        email: data.email,
        role: data.role,
        invitedBy: data.invitedBy,
        expiresAt,
      },
    });

    return invitation;
  }
}

export default new WorkspaceService();

import jwt, { JwtPayload } from 'jsonwebtoken';
import bcrypt from 'bcryptjs';

// 🔐 Env config
const JWT_SECRET: string = process.env.JWT_SECRET || 'your_super_secret_jwt_key';
const JWT_EXPIRY = '7d';

// 📌 Token payload type
interface TokenPayload extends JwtPayload {
  userId: string
}

// ✅ Generate JWT token
export const generateToken = (userId: string): string => {
  return jwt.sign({ userId }, JWT_SECRET, {
    expiresIn: JWT_EXPIRY,
  });
};

// ✅ Verify JWT token
export const verifyToken = (token: string): TokenPayload | null => {
  try {
    return jwt.verify(token, JWT_SECRET) as TokenPayload;
  } catch (error) {
    return null;
  }
};

// 🔐 Hash password
export const hashPassword = async (password: string): Promise<string> => {
  return await bcrypt.hash(password, 10);
};

// 🔐 Compare password
export const comparePassword = async (
  password: string,
  hash: string,
): Promise<boolean> => {
  return await bcrypt.compare(password, hash);
};

