import winston from 'winston';
import path from 'path';

const levels = {
  error: 0,
  warn: 1,
  info: 2,
  http: 3,
  debug: 4,
};

const colors = {
  error: 'red',
  warn: 'yellow',
  info: 'green',
  http: 'magenta',
  debug: 'white',
};

winston.addColors(colors);

const format = winston.format.combine(
  winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss:ms' }),
  winston.format.printf(
    (info) => `${info.timestamp} ${info.level}: ${info.message}`,
  ),
);

const transports = [
  // Console transport
  new winston.transports.Console(),
  // File transport for errors
  new winston.transports.File({
    filename: path.join('logs', 'error.log'),
    level: 'error',
  }),
  // File transport for all logs
  new winston.transports.File({
    filename: path.join('logs', 'all.log'),
  }),
];

const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'debug',
  levels,
  format,
  transports,
});

export default logger;

/**
 * HTTP request logger middleware
 */
export const requestLogger = (req: any, res: any, next: any) => {
  const start = Date.now();

  res.on('finish', () => {
    const duration = Date.now() - start;
    const level = res.statusCode >= 400 ? 'warn' : 'http';

    logger.log(
      level,
      `${req.method} ${req.originalUrl} ${res.statusCode} ${duration}ms`,
    );
  });

  next();
};

import { Response } from 'express';
import { AppError, ErrorCode } from './errors';

export interface ApiResponse<T = any> {
  success: boolean;
  statusCode: number;
  message: string;
  data?: T;
  error?: {
    code: ErrorCode;
    details?: Record<string, any>;
  };
  timestamp: string;
}

/**
 * Format success response
 */
export const successResponse = <T>(
  res: Response,
  statusCode: number,
  message: string,
  data?: T,
): Response => {
  const response: ApiResponse<T> = {
    success: true,
    statusCode,
    message,
    data,
    timestamp: new Date().toISOString(),
  };
  return res.status(statusCode).json(response);
};

/**
 * Format error response
 */
export const errorResponse = (
  res: Response,
  statusCode: number,
  message: string,
  errorCode: ErrorCode,
  details?: Record<string, any>,
): Response => {
  const response: ApiResponse = {
    success: false,
    statusCode,
    message,
    error: {
      code: errorCode,
      details,
    },
    timestamp: new Date().toISOString(),
  };
  return res.status(statusCode).json(response);
};

/**
 * Format AppError response
 */
export const appErrorResponse = (res: Response, error: AppError): Response => {
  const details = (error as any).details;
  return errorResponse(
    res,
    error.statusCode,
    error.message,
    error.errorCode,
    details,
  );
};

/**
 * Generic error response handler
 */
export const handleErrorResponse = (res: Response, error: any): Response => {
  if (error instanceof AppError) {
    return appErrorResponse(res, error);
  }

  // Handle Joi validation errors
  if (error.isJoi) {
    return errorResponse(
      res,
      400,
      'Validation error',
      ErrorCode.VALIDATION_ERROR,
      {
        details: error.details?.map((d: any) => ({
          field: d.path.join('.'),
          message: d.message,
          type: d.type,
        })),
      },
    );
  }

  // Generic error
  return errorResponse(
    res,
    500,
    'Internal server error',
    ErrorCode.INTERNAL_SERVER_ERROR,
  );
};

